import React from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import Books from './pages/Books';
import IssuedBooks from './pages/IssuedBooks';

export default function App() {
  return (
    <BrowserRouter>
      <Navbar />
      <Routes>
        <Route path='/' element={<Home />} />
        <Route path='/books' element={<Books />} />
        <Route path='/issued-books' element={<IssuedBooks />} />
      </Routes>
    </BrowserRouter>
  );
}

import React from 'react';
import { NavLink } from 'react-router-dom';

export default function Navbar() {
  const linkStyle = ({ isActive }) => ({
    textDecoration: 'none',
    color: isActive ? '#0f172a' : '#64748b',
    fontWeight: isActive ? 700 : 500
  });

  return (
    <nav style={{ borderBottom: '1px solid #e2e8f0', background: '#ffffff' }}>
      <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '16px 24px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <h2 style={{ margin: 0 }}>LibraryHub</h2>
        <div style={{ display: 'flex', gap: '18px' }}>
          <NavLink to='/' style={linkStyle}>Home</NavLink>
          <NavLink to='/books' style={linkStyle}>Books</NavLink>
          <NavLink to='/issued-books' style={linkStyle}>Issued Books</NavLink>
        </div>
      </div>
    </nav>
  );
}

import React from 'react';

export default function BookCard({ book }) {
  return (
    <div style={{ border: '1px solid #e2e8f0', borderRadius: '14px', padding: '16px', background: '#fff', boxShadow: '0 2px 8px rgba(0,0,0,0.04)' }}>
      <h3 style={{ marginTop: 0 }}>{book.title}</h3>
      <p style={{ color: '#64748b', margin: '6px 0' }}>Author: {book.author}</p>
      <p style={{ color: '#64748b', margin: '6px 0' }}>Category: {book.category}</p>
      <p style={{ fontWeight: 600 }}>Status: {book.availability_status}</p>
      <button style={{ marginTop: '10px', padding: '10px 14px', borderRadius: '10px', border: 'none', background: '#0f172a', color: '#fff', cursor: 'pointer' }}>
        Issue Book
      </button>
    </div>
  );
}

import React from 'react';

export default function Home() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <div style={{ background: '#f8fafc', border: '1px solid #e2e8f0', borderRadius: '18px', padding: '32px' }}>
        <h1 style={{ marginTop: 0 }}>Library made simple</h1>
        <p style={{ maxWidth: '720px', color: '#475569' }}>
          Search available books, issue them easily, and keep track of your due dates from one student-friendly portal.
        </p>
        <div style={{ display: 'flex', gap: '12px', marginTop: '20px' }}>
          <a href='/books' style={{ textDecoration: 'none', padding: '10px 16px', background: '#0f172a', color: '#fff', borderRadius: '10px' }}>Browse Books</a>
          <a href='/issued-books' style={{ textDecoration: 'none', padding: '10px 16px', background: '#e2e8f0', color: '#0f172a', borderRadius: '10px' }}>View Due Dates</a>
        </div>
      </div>
    </div>
  );
}

import React from 'react';
import BookCard from '../components/BookCard';

const books = [
  { id: 1, title: 'Database Systems', author: 'Korth', category: 'CS', availability_status: 'Available' },
  { id: 2, title: 'Discrete Mathematics', author: 'Rosen', category: 'Math', availability_status: 'Available' },
  { id: 3, title: 'Operating Systems', author: 'Silberschatz', category: 'CS', availability_status: 'Issued' }
];

export default function Books() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: '16px', marginBottom: '20px', flexWrap: 'wrap' }}>
        <h1 style={{ margin: 0 }}>Books</h1>
        <input placeholder='Search books...' style={{ minWidth: '260px', padding: '10px 12px', borderRadius: '10px', border: '1px solid #cbd5e1' }} />
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', gap: '18px' }}>
        {books.map(book => <BookCard key={book.id} book={book} />)}
      </div>
    </div>
  );
}

import React from 'react';

const issuedBooks = [
  { id: 1, title: 'Computer Networks', issue_date: '2026-03-10', due_date: '2026-03-24' },
  { id: 2, title: 'Software Engineering', issue_date: '2026-03-14', due_date: '2026-03-28' }
];

export default function IssuedBooks() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Issued Books</h1>
      <div style={{ border: '1px solid #e2e8f0', borderRadius: '14px', overflow: 'hidden' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead style={{ background: '#f8fafc' }}>
            <tr>
              <th style={{ textAlign: 'left', padding: '14px' }}>Title</th>
              <th style={{ textAlign: 'left', padding: '14px' }}>Issue Date</th>
              <th style={{ textAlign: 'left', padding: '14px' }}>Due Date</th>
            </tr>
          </thead>
          <tbody>
            {issuedBooks.map(book => (
              <tr key={book.id}>
                <td style={{ padding: '14px', borderTop: '1px solid #f1f5f9' }}>{book.title}</td>
                <td style={{ padding: '14px', borderTop: '1px solid #f1f5f9' }}>{book.issue_date}</td>
                <td style={{ padding: '14px', borderTop: '1px solid #f1f5f9' }}>{book.due_date}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

from flask import Flask, jsonify

app = Flask(__name__)

@app.route('/api/books')
def get_books():
    return jsonify({
        'books': [
            {'id': 1, 'title': 'Database Systems', 'author': 'Korth', 'category': 'CS', 'availability_status': 'Available'},
            {'id': 2, 'title': 'Discrete Mathematics', 'author': 'Rosen', 'category': 'Math', 'availability_status': 'Available'},
            {'id': 3, 'title': 'Operating Systems', 'author': 'Silberschatz', 'category': 'CS', 'availability_status': 'Issued'}
        ]
    })

@app.route('/api/issued-books')
def get_issued_books():
    return jsonify({
        'issued_books': [
            {'id': 1, 'title': 'Computer Networks', 'issue_date': '2026-03-10', 'due_date': '2026-03-24'},
            {'id': 2, 'title': 'Software Engineering', 'issue_date': '2026-03-14', 'due_date': '2026-03-28'}
        ]
    })

if __name__ == '__main__':
    app.run(debug=True)
